// Package pve embeds the committed Proxmox VE API schema snapshot and exposes
// it as a parsed IR. The snapshot is regenerated by cmd/schemagen; this package
// is intentionally separate from internal/schema so that schemagen (which
// imports internal/schema) can build even before the snapshot file exists.
package pve

import (
	_ "embed"
	"sync"

	"github.com/ciroiriarte/pve-cli/internal/schema"
)

//go:embed apischema.json
var snapshot []byte

var (
	once   sync.Once
	cached *schema.API
	cerr   error
)

// Schema returns the embedded PVE API schema, parsing it once and caching the
// result.
func Schema() (*schema.API, error) {
	once.Do(func() {
		cached, cerr = schema.LoadBytes(snapshot)
	})
	return cached, cerr
}
